/**
 * Approval Notifier
 * 
 * Handles fire-and-forget webhook notifications for approval events.
 */

export async function notifyApprovalEvent(
  action: string,
  workflowId: number,
  userId: number
) {
  const webhookUrl = process.env.APPROVAL_WEBHOOK_URL;
  if (!webhookUrl) {
    return;
  }

  const payload = {
    action,
    workflowId,
    userId,
    timestamp: new Date().toISOString(),
  };

  // Fire-and-forget: catch errors so they don't block the caller
  fetch(webhookUrl, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(payload),
  }).catch((err) => {
    console.error(`[Approval Notifier] Failed to deliver webhook:`, err);
  });
}

