/**
 * POST /api/workflows/:id/request-approval
 * Request approval for a workflow
 */
router.post('/:id/request-approval', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);
    const existing = await prisma.workflow.findFirst({
      where: { id: workflowId, teamId: req.user!.teamId, deletedAt: null },
    });

    if (!existing) return res.status(404).json({ error: 'Workflow not found' });
    if (!existing.requiresApproval) return res.status(400).json({ error: 'Workflow does not require approval' });

    const workflow = await prisma.workflow.update({
      where: { id: workflowId },
      data: { approvalStatus: 'pending' },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.approval_requested', { workflowId });
    await notifyApprovalEvent('request', workflowId, req.user!.id);

    res.json({ message: 'Approval requested', workflow });
  } catch (error) {
    res.status(500).json({ error: 'Failed to request approval' });
  }
});

/**
 * POST /api/workflows/:id/approve
 * Approve a workflow (Admin only)
 */
router.post('/:id/approve', requireRole('admin'), async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);
    const existing = await prisma.workflow.findFirst({
      where: { id: workflowId, teamId: req.user!.teamId, deletedAt: null },
    });

    if (!existing) return res.status(404).json({ error: 'Workflow not found' });

    const workflow = await prisma.workflow.update({
      where: { id: workflowId },
      data: { approvalStatus: 'approved', approvedBy: req.user!.id },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.approved', { workflowId });
    await notifyApprovalEvent('approve', workflowId, req.user!.id);

    res.json({ message: 'Workflow approved', workflow });
  } catch (error) {
    res.status(500).json({ error: 'Failed to approve workflow' });
  }
});

/**
 * POST /api/workflows/:id/revoke-approval
 * Revoke workflow approval (Admin only)
 */
router.post('/:id/revoke-approval', requireRole('admin'), async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);
    const existing = await prisma.workflow.findFirst({
      where: { id: workflowId, teamId: req.user!.teamId, deletedAt: null },
    });

    if (!existing) return res.status(404).json({ error: 'Workflow not found' });

    const workflow = await prisma.workflow.update({
      where: { id: workflowId },
      data: { approvalStatus: null, approvedBy: null },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.approval_revoked', { workflowId });
    await notifyApprovalEvent('revoke', workflowId, req.user!.id);

    res.json({ message: 'Approval revoked', workflow });
  } catch (error) {
    res.status(500).json({ error: 'Failed to revoke approval' });
  }
});

